INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES
(15, 1, '16', '자산배분 중요성', '노벨 경제학상 수상자 해리 마코위츠가 자산배분을 가리켜 표현한 말은?', '"투자의 철칙"', '"금융 시장에서 유일한 공짜 점심"', '"최고의 수익 공식"', '"리스크 제로 전략"', 2, '문서에서 마코위츠는 자산배분을 "금융 시장에서 유일한 공짜 점심(The only free lunch in investing)"이라고 표현했습니다.'),
(15, 2, '16', '자산배분 중요성', '자산배분의 4가지 목적 중 "복리 효과의 보호"와 관련된 관리 지표는?', 'PER', 'EPS', 'MDD', '듀레이션', 3, '문서에서 복리 효과의 보호는 최대 낙폭(MDD, Maximum Drawdown) 관리와 직결된다고 설명합니다.'),
(15, 3, '16', '자산배분 중요성', '학계 연구에 따르면 포트폴리오 장기 성과에서 자산배분이 차지하는 비중은?', '50% 이상', '70% 이상', '80% 이상', '90% 이상', 4, '문서에 "자산배분이 차지하는 비중은 90% 이상"이라고 명시되어 있습니다.'),
(15, 4, '16', '오늘 배울 것', '문서(Day 056)의 "오늘 배울 것"에 포함되지 않은 것은?', '평균분산 최적화(Mean-Variance Optimization)', '블랙-리터만(Black-Litterman) 모델 개요', '듀레이션 면역 전략', 'Risk-Parity 모델 개요', 3, '"오늘 배울 것" 목록에는 평균분산 최적화, 블랙-리터만, Risk-Parity, 사례 분석, 실습이 제시됩니다. 듀레이션 면역 전략은 포함되지 않습니다.'),
(15, 5, '16', '세부 일정', '세부 일정에서 09:10–09:30 1단락 설명 주제는?', '블랙-리터만 모델', '평균분산 최적화', 'Risk-Parity 모델', '60/40 사례 분석', 2, '세부 일정 표에서 09:10–09:30은 "평균분산 최적화" 강의입니다.'),
(15, 6, '16', '세부 일정', '세부 일정에서 11:00–11:20 3단락 설명 주제는?', '평균분산 최적화', '블랙-리터만 모델', 'Risk-Parity 모델', '60/40, All Weather 사례', 3, '세부 일정에서 11:00–11:20은 "Risk-Parity 모델" 강의입니다.'),
(15, 7, '16', '세부 일정', '세부 일정에서 실습 1부(14:00–15:00) 내용은?', '최적 비중 계산 및 백테스트', '전략별 장단점 발표', '기대수익률·공분산 행렬 계산', '60/40과 Risk-Parity 비교', 3, '세부 일정에서 실습 1부(14:00–15:00)는 "기대수익률·공분산 행렬 계산"입니다.'),
(15, 8, '16', '평균분산 최적화', '평균분산 최적화 예시 코드에서 weights 배열 값으로 사용된 것은?', '[0.4, 0.3, 0.3]', '[0.5, 0.3, 0.2]', '[0.6, 0.2, 0.2]', '[0.3, 0.4, 0.3]', 2, '예시 코드에서 weights = np.array([0.5, 0.3, 0.2])로 설정되어 있습니다.'),
(15, 9, '16', '평균분산 최적화', '예시 코드에서 포트폴리오 기대수익률을 계산하는 연산식은?', 'weights.sum() / expected_returns.sum()', 'weights @ expected_returns', 'np.dot(expected_returns, expected_returns)', 'weights * expected_returns.mean()', 2, '코드에서 portfolio_return = weights @ expected_returns (내적) 으로 계산합니다.'),
(15, 10, '16', '블랙-리터만 모델', '블랙-리터만 모델을 사용하는 주요 이유로 문서에 제시된 것은?', '거래비용을 최소화하기 위해', '평균분산 최적화의 입력값 민감도 문제를 완화하기 위해', '공분산 행렬 계산을 생략하기 위해', '배당수익률 예측 정확도를 높이기 위해', 2, '문서에서 블랙-리터만은 평균분산 최적화가 입력값에 민감하다는 문제를 완화하기 위해 사용된다고 설명합니다.'),
(15, 11, '16', '블랙-리터만 모델', '예시 코드에서 confidence 값으로 사용된 것은?', '0.1', '0.3', '0.5', '0.8', 3, '코드에 confidence = 0.5로 설정되어 있습니다.'),
(15, 12, '16', 'Risk-Parity 모델', 'Risk-Parity 역변동성 예시 코드에서 SPY의 변동성 값은?', '0.12', '0.15', '0.18', '0.22', 3, '코드에서 volatility = pd.Series({"SPY": 0.18, ...})로 SPY 변동성이 0.18로 설정됩니다.'),
(15, 13, '16', '자산배분 사례', 'Permanent Portfolio의 기본 구성으로 옳은 것은?', '주식 50%, 채권 30%, 금 20%', '주식 60%, 채권 40%', '주식 30%, 장기채 40%, 원자재 15%, 금 15%', '주식, 장기채, 현금, 금 각 25%', 4, '문서 표에서 Permanent Portfolio는 주식, 장기채, 현금, 금을 각 25%씩 배분하는 모델입니다.'),
(15, 14, '16', '실습 코드', '실습 예시 코드에서 무작위 포트폴리오를 생성하는 반복 횟수는?', '1000', '2000', '3000', '5000', 4, '코드에서 for _ in range(5000)으로 5,000개의 무작위 포트폴리오를 생성합니다.'),
(15, 15, '16', '다음 시간 미리보기', '문서 마지막에 예고된 다음 모듈 주제는?', '채권 가격과 듀레이션 기초', '퀀트 전략 설계와 백테스트 구현', '자산배분 규제 개요', '재무제표 분석 심화', 2, '문서 마지막에 "다음 모듈에서는 퀀트 전략 설계와 백테스트 구현으로 이어집니다"라고 안내합니다.'),
(15, 16, '17', '금융회사 종류', '자본시장법을 근거 법률로 하는 금융회사 유형은?', '은행', '금융투자업자', '보험회사', '저축은행', 2, '문서 표에서 금융투자업자의 근거 법률은 자본시장법이고, 은행은 은행법, 보험회사는 보험업법, 저축은행은 상호저축은행법입니다.'),
(15, 17, '17', '금융회사 종류', '한국의 비은행금융회사를 이해하는 5개 그룹 중 해당하지 않는 것은?', '비은행예금취급기관', '금융투자업자', '보험회사', '중앙은행', 4, '문서에서 비은행금융회사 5개 그룹은 ①비은행예금취급기관, ②금융투자업자, ③보험회사, ④여신전문금융회사, ⑤기타입니다. 중앙은행은 해당하지 않습니다.'),
(15, 18, '17', '수신·여신', '수신(受信)의 의미로 가장 적절한 것은?', '금융회사가 고객에게 돈을 빌려주는 것', '금융회사가 고객에게 돈을 받는 것(예금)', '금융회사가 채권을 발행해 자금을 조달하는 것', '금융회사 간 자금을 청산하는 것', 2, '문서 표에서 수신은 "금융회사가 고객에게 돈을 받는 것(예금)"으로 정의됩니다.'),
(15, 19, '17', '수신·여신', '여신전문금융회사가 예금자보호 대상이 아닌 근본 이유는?', '자기자본이 부족하기 때문', '수신(예금)을 받지 않기 때문', '금융위원회 인가를 받지 않기 때문', '해외 자본이 지분을 보유하기 때문', 2, '문서에서 여신전문금융회사는 수신(예금)을 받지 않으므로 예금자보호 대상이 아니라고 설명합니다.'),
(15, 20, '17', '증권회사', '증권회사 브로커리지(위탁매매)의 주요 수익원은?', '인수 수수료', '거래 수수료', '자문 보수', '매매 차익', 2, '문서 표에서 브로커리지(위탁매매)의 수익원은 "거래 수수료"입니다.'),
(15, 21, '17', '증권회사', '종합금융투자사업자(대형 증권사)의 자기자본 기준은?', '5,000억원 이상', '1조원 이상', '2조원 이상', '3조원 이상', 4, '문서에서 종합금융투자사업자는 자기자본 3조원 이상인 대형 증권사라고 명시합니다.'),
(15, 22, '17', '증권회사', '증권사 계좌 중 하루짜리 단기 투자(RP·MMF)가 가능한 입출금 자유 계좌는?', 'ISA', 'IRP', 'Wrap Account', 'CMA', 4, '문서 표에서 CMA는 RP·MMF 방식의 하루짜리 단기 투자가 가능하고 입출금이 자유롭습니다.'),
(15, 23, '17', '핀테크', '오픈뱅킹의 건당 이체 수수료로 문서에 제시된 금액은?', '10원', '20원', '40원', '100원', 3, '문서에서 오픈뱅킹 수수료는 "건당 40원(기존 수백 원 → 대폭 인하)"로 명시되어 있습니다.'),
(15, 24, '17', '핀테크', '마이데이터(본인신용정보관리업) 서비스가 시행된 시점은?', '2019년 10월', '2020년 1월', '2022년 1월', '2023년 3월', 3, '문서에서 마이데이터는 2022년 1월(신용정보법 개정)에 시행되었다고 명시합니다.'),
(15, 25, '17', '핀테크', '가상자산사업자(VASP)의 근거 법률은?', '자본시장법', '전자금융거래법', '특정금융정보법', '은행법', 3, '문서에서 가상자산사업자의 근거 법률은 특정금융정보법(특금법) 제7조라고 설명합니다.'),
(15, 26, '17', '핀테크', '인터넷전문은행이 핀테크 앱(전자금융업자)과 구별되는 결정적 차이는?', '앱 기반으로만 서비스를 제공한다', '예금 수신이 가능하고 예금자보호를 받는다', '금융위원회의 규제를 전혀 받지 않는다', '가상자산 거래를 직접 중개할 수 있다', 2, '문서 표에서 인터넷전문은행은 예금 수신이 가능하고 예금자보호법(5천만원)이 적용되는 반면, 전자금융업자는 수신이 불가합니다.'),
(15, 27, '17', '핀테크', 'PG사(전자지급결제대행업자)의 수수료 범위로 문서에 제시된 것은?', '0.01~0.1%', '0.1~0.5%', '1~3%', '3~5%', 2, '문서에서 PG사의 수익은 "결제 금액의 0.1~0.5% 수수료"라고 명시합니다.'),
(15, 28, '17', '예금자보호', '우체국 예금의 예금자보호 방식은?', '예금자보호법 5천만원 한도', '정부가 원금 전액 보장', '새마을금고중앙회 기금 5천만원', '신협자체기금 5천만원', 2, '문서에서 우체국은 정부가 원금 전액 보장하는 방식으로 예금자를 보호한다고 명시합니다.'),
(15, 29, '17', '벤처캐피탈', 'VC(벤처캐피탈)의 근거 법률로 문서에 제시된 것은?', '자본시장법', '여신전문금융업법', '벤처투자법', '신용정보법', 3, '문서 표에서 VC의 근거 법률은 "벤처투자법, 중소기업창업지원법"이며 규제 기관은 중소벤처기업부입니다.'),
(15, 30, '17', '신용카드', '신용카드 서비스 중 리볼빙(revolving)의 특징으로 옳은 것은?', '다음달 전액 상환, 이자 없음', '여러 달로 나눠 상환, 3개월 미만 무이자 가능', '최소 금액만 납부하고 잔액 이월, 연 이자율 15~20%', '카드 한도 내 단기 대출, 연 이자율 10~20%', 3, '문서 표에서 리볼빙은 "최소 금액만 납부하고 잔액 이월, 연 이자율 15~20%"로 설명됩니다.');
